document.querySelectorAll('[id="year"]').forEach(yearEl=>{yearEl.textContent=new Date().getFullYear()});const loadingScreen=document.getElementById("loading-screen"),pageShell=document.getElementById("page-shell");loadingScreen&&pageShell&&window.addEventListener("load",()=>{setTimeout(()=>{loadingScreen.classList.add("hidden"),pageShell.classList.add("visible")},1400)});const newsletterForms=document.querySelectorAll(".newsletter-form");newsletterForms.forEach(form=>{form.addEventListener("submit",event=>{event.preventDefault();const input=form.querySelector("input");if(input){input.value="";const button=form.querySelector("button");if(button){button.dataset.originalText||(button.dataset.originalText=button.textContent||"Subscribe"),button.textContent="Thanks!",setTimeout(()=>{button.textContent=button.dataset.originalText},1600)}}})});const backToTop=document.getElementById("backToTop");backToTop&&(window.addEventListener("scroll",()=>{backToTop.classList.toggle("visible",window.scrollY>420)}),backToTop.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth"})}));const transitionOverlay=document.getElementById("page-transition"),internalLinks=Array.from(document.querySelectorAll("a[href]"));internalLinks.forEach(link=>{if(link.target==="_blank"||link.hasAttribute("download"))return;link.addEventListener("click",event=>{const href=link.getAttribute("href");if(!href||href.startsWith("#")||href.startsWith("mailto:")||href.startsWith("tel:")||href.startsWith("javascript:"))return;const url=new URL(href,window.location.href);if(url.origin!==window.location.origin)return;event.preventDefault(),transitionOverlay&&transitionOverlay.classList.add("active"),window.setTimeout(()=>{window.location.assign(url.href)},180)})});const prefersReducedMotion=window.matchMedia("(prefers-reduced-motion: reduce)").matches,scene=document.querySelector("[data-parallax]");if(scene&&!prefersReducedMotion){let frameId=null,lastX=0,lastY=0;const updateScene=()=>{scene.style.transform=`translate3d(${lastX}px, ${lastY}px, 0)`,frameId=null};window.addEventListener("pointermove",event=>{const{innerWidth:innerWidth,innerHeight:innerHeight}=window;lastX=(event.clientX/innerWidth-.5)*12,lastY=(event.clientY/innerHeight-.5)*12,frameId||window.requestAnimationFrame(updateScene)}),window.addEventListener("pointerleave",()=>{scene.style.transform="translate3d(0, 0, 0)"})}const tiltItems=document.querySelectorAll("[data-tilt]");tiltItems.forEach(item=>{if(prefersReducedMotion)return;let frameId=null,lastX=0,lastY=0;const updateTilt=()=>{item.style.transform=`perspective(1000px) rotateY(${lastX}deg) rotateX(${-lastY}deg)`,frameId=null};item.addEventListener("pointermove",event=>{const rect=item.getBoundingClientRect();lastX=((event.clientX-rect.left)/rect.width-.5)*10,lastY=((event.clientY-rect.top)/rect.height-.5)*10,frameId||window.requestAnimationFrame(updateTilt)}),item.addEventListener("pointerleave",()=>{item.style.transform="perspective(1000px) rotateY(0deg) rotateX(0deg)"})});
